#include<bits/stdc++.h>
using namespace std;
int main() {
	string a,b,c="0123456789X";
	int d=0,k=0;
	cin >> a;
	for (int i = 0; i < a.size()-1;i++) {
		if(a[i]!='-')
		{d += (int(a[i])-48) * ++k;}
	}
	d%=11;
	if (a[12]!=c[d]) {
		b=a;
		b[12]=c[d];
		cout<<b;
	} else {
		cout<<"Right";
	}
	
	
	
	
	
	
	
}
